#' Determine Optimal Lag Order for VAR Model Using Information Criteria
#'
#' Fits VAR models for lag orders 1 through \code{pmax} and returns the lag
#' length that minimises each of three information criteria.
#'
#' @param y A T x N matrix of endogenous variables (T observations, N series).
#' @param pmax An integer specifying the maximum VAR lag order to consider.
#' @param c An integer (0 or 1) indicating whether to include a constant term
#'   (1 = include, 0 = exclude).
#' @param exog An optional T x M matrix of exogenous variables. Default is
#'   NULL.
#'
#' @return A list with three integer elements: aic — optimal lag length by
#'   Akaike IC; bic — optimal lag length by Bayesian IC; hq — optimal lag
#'   length by Hannan-Quinn IC.
#'
#' @details
#' For each candidate lag order p the residual covariance Sigma = (e'e)/T is
#' computed and the three criteria are evaluated as:
#'
#' AIC = log(det(Sigma)) + 2 * (p*N^2 + N + M) / T
#'
#' BIC = log(det(Sigma)) + log(T) * (p*N^2 + N + M) / T
#'
#' HQ  = log(det(Sigma)) + 2 * log(log(T)) * (p*N^2 + N + M) / T
#'
#' where M is the number of exogenous variables.
#'
#' @examples
#' \dontrun{
#' set.seed(123)
#' y      <- matrix(rnorm(200), ncol = 2)
#' result <- fAICBIC(y, pmax = 10, c = 1)
#' result$aic
#' result$bic
#' }
#'
#' @seealso \code{\link{fVAR}}
#'
#' @export
fAICBIC <- function(y, pmax, c, exog = NULL) {
    .Call(`_tidyMacro_fAICBIC`, y, pmax, c, exog)
}

#' Ordinary Least Squares Regression
#'
#' @param y Dependent variable matrix! not vector
#' @param X Independent variables matrix (T x N)
#' @param c Integer indicator for intercept (1 if intercept included, 0 otherwise)
#'
#' @return A list containing:
#'   \itemize{
#'     \item beta: Coefficient estimates ((N+1) x 1 if c=1, N x 1 if c=0)
#'     \item fitted: Fitted values (T x 1)
#'     \item err: Residuals (T x 1)
#'     \item r2: R-squared statistic (scalar)
#'     \item fitted_partial: Fitted values excluding intercept (T x 1)
#'   }
#'
#' @details
#' This function performs ordinary least squares (OLS) regression. The coefficient
#' estimates are computed using the normal equations:
#' \deqn{\hat{\beta} = (X'X)^{-1}X'y}
#'
#' The R-squared statistic measures the proportion of variance explained:
#' \deqn{R^2 = 1 - \frac{RSS}{TSS}}
#' where RSS is the residual sum of squares and TSS is the total sum of squares.
#'
#' If an intercept is included (c=1), fitted_partial contains the fitted values
#' excluding the intercept contribution, useful for assessing the explanatory
#' power of the regressors alone.
#'
#' @examples
#' \dontrun{
#' # Generate sample data
#' set.seed(123)
#' y <- rnorm(100)
#' X <- matrix(rnorm(200), 100, 2)
#' 
#' # OLS with intercept
#' result <- fOLS(y, X, c = 1)
#' print(result$beta)
#' print(result$r2)
#' 
#' # OLS without intercept
#' result_no_int <- fOLS(y, X, c = 0)
#' }
#'
#' @export
fOLS <- function(y, X, c = 1L) {
    .Call(`_tidyMacro_fOLS`, y, X, c)
}

#' Print SVAR Identification Steps
#'
#' Prints a numbered guide to the proxy-SVAR identification and
#' invertibility-testing procedure to the R console.
#'
#' @return Called for its side-effect of printing to the console.
#'   Returns \code{NULL} invisibly.
#'
#' @details
#' Step 1: Estimate the VAR(p) and extract the residuals.
#'
#' Step 2: Regress the instrument on the current residuals plus f leads;
#' save the fitted value.
#'
#' Step 3: F-test whether the lead coefficients are jointly zero. Rejection
#' implies the shock is non-invertible.
#'
#' Step 4: If invertible, apply the standard Stock-Watson IV procedure to
#' obtain IRFs and unit-variance shocks.
#'
#' Step 5: If non-invertible, test recoverability via the Ljung-Box test on
#' the fitted instrument series.
#'
#' Step 6: If recoverable (null of no autocorrelation not rejected), repeat
#' the IV procedure adding residual leads to the first-stage regression.
#'
#' Step 7: If recoverability is rejected, SVAR analysis with this instrument
#' is not feasible.
#'
#' @examples
#' fSVAR_steps()
#'
#' @export
fSVAR_steps <- function() {
    invisible(.Call(`_tidyMacro_fSVAR_steps`))
}

#' Vector Autoregression (VAR) Model Estimation
#'
#' Estimates a Vector Autoregression model with optional exogenous variables
#' using ordinary least squares (OLS). Optimised for maximum speed and memory
#' efficiency via RcppArmadillo.
#'
#' @param y A numeric matrix of time series data with T rows (time periods)
#'   and N columns (endogenous variables).
#' @param p An integer specifying the number of lags to include in the VAR.
#' @param c An integer indicator for including a constant term (1 = include
#'   intercept, 0 = no intercept).
#' @param exog An optional T x M matrix of exogenous variables. If provided,
#'   these variables enter contemporaneously (not lagged). Default is NULL.
#'
#' @return A list with elements: beta — coefficient matrix of dimensions
#'   (Np + c + M) x N, where the first row is the intercept (if c = 1),
#'   followed by N*p lag-coefficient rows, then M exogenous-coefficient rows;
#'   residuals — (T-p) x N matrix of OLS residuals;
#'   sigma_full — N x N residual covariance matrix normalised by (n_obs - 1);
#'   p — lag order (echoed from input);
#'   c — intercept indicator (echoed from input);
#'   n_exog — number of exogenous variables (0 if none provided).
#'
#' @details
#' The model is \deqn{Y_t = c + A_1 Y_{t-1} + \cdots + A_p Y_{t-p} + B X_t + e_t}
#' where \eqn{X_t} are contemporaneous exogenous variables. Without exogenous
#' variables the model reduces to a standard VAR(p). Estimation uses
#' \code{arma::solve} for numerical stability.
#'
#' @examples
#' \dontrun{
#' # VAR(2) without exogenous variables
#' y      <- matrix(rnorm(200), ncol = 2)
#' result <- fVAR(y, p = 2, c = 1)
#'
#' # VAR(2) with one exogenous variable
#' exog   <- matrix(rnorm(100), ncol = 1)
#' result <- fVAR(y, p = 2, c = 1, exog = exog)
#' }
#'
#' @seealso \code{\link{fwoldIRF}}, \code{\link{fbootstrapChol}},
#'   \code{\link{fAICBIC}}
#'
#' @export
fVAR <- function(y, p, c, exog = NULL) {
    .Call(`_tidyMacro_fVAR`, y, p, c, exog)
}

#' Vector Autoregression with Exogenous Variables (VARX) Model Estimation
#'
#' Estimates a VARX(p) model where both endogenous and exogenous variables
#' are lagged using ordinary least squares (OLS). Optimised for maximum
#' speed and memory efficiency.
#'
#' @param y A numeric matrix of endogenous time series data with T rows
#'   (time periods) and N columns (variables).
#' @param ex A numeric matrix of exogenous time series data with T rows
#'   (time periods) and M columns (variables).
#' @param p An integer specifying the number of lags for both endogenous
#'   and exogenous variables.
#' @param c An integer indicator for including a constant term (1 = include
#'   intercept, 0 = no intercept).
#'
#' @return A list with two elements: beta — coefficient matrix of dimensions
#'   (Np + M + Mp + c) x N; residuals — (T-p) x N residual matrix.
#'
#' @details
#' The VARX(p) model is:
#' \deqn{Y_t = c + A_1 Y_{t-1} + \cdots + A_p Y_{t-p}
#'            + B_0 X_t + B_1 X_{t-1} + \cdots + B_p X_{t-p} + e_t}
#' Both endogenous and exogenous variables are lagged p periods.
#' Exogenous variables also enter contemporaneously at time t.
#'
#' @examples
#' \dontrun{
#' y  <- matrix(rnorm(200), ncol = 2)
#' ex <- matrix(rnorm(100), ncol = 1)
#' result    <- fVARX(y, ex, p = 2, c = 1)
#' beta      <- result$beta
#' residuals <- result$residuals
#' }
#'
#' @export
fVARX <- function(y, ex, p, c) {
    .Call(`_tidyMacro_fVARX`, y, ex, p, c)
}

